// NQxb_Demo_Proxy_v1__Enforce_And_Translate
// Governance: docs/design/Design__Explore_Qwrk_Demo_Governance__v1.md v1.2
// Purpose: All enforcement (rate limit, action/type allowlist, size limits,
//          tag governance) + payload translation to Gateway canonical format.
//
// NOTE: parent_artifact_id is NOT supported in v1.
//       Requests with parent_artifact_id are rejected.
//       Parent-linked artifacts deferred to v2.
//
// FIX: Extension injection for type-specific required fields.
//   - project: extension.lifecycle_stage = "seed" (NOT NULL in DDL)
//   - snapshot: extension.payload = content or {} (NOT NULL in DDL)
//   - journal: extension.entry_text = summary or null (nullable)

const DEMO_WS  = "0af5712b-2534-47c1-8e28-45be4a2131dc";
const OWNER    = "c52c7a57-74ad-433d-a07c-4dcac1778672";
const SEM_TYPE = "exploratory";
const MUST_TAGS = ["demo-mode", "explore-qwrk"];
const BAN_TAGS  = new Set(["demo-seed", "for-q", "for-cc"]);

const OK_ACTIONS = new Set(["artifact.save", "artifact.list", "artifact.query"]);
const OK_TYPES   = new Set(["journal", "project", "snapshot"]);

function err(code, msg) {
  return [{ json: { _route: "error", ok: false, error: { code, message: msg } } }];
}

// ── Rate Limiting (in-memory counters, per governance §11) ──
const sd = $getWorkflowStaticData("global");
const now = Date.now();
if (!sd.t || (now - sd.t) > 60000) {
  sd.t = now;
  sd.g = 0;
  sd.ip = {};
}
const ip = String($json.headers?.["x-forwarded-for"] ?? "").split(",")[0].trim() || "unknown";
sd.g = (sd.g || 0) + 1;
sd.ip = sd.ip || {};
sd.ip[ip] = (sd.ip[ip] || 0) + 1;
if (sd.g > 50 || sd.ip[ip] > 10) {
  return err("RATE_LIMIT_EXCEEDED",
    "The demo is receiving a lot of activity right now. Please try again in a moment.");
}

// ── Extract request body ──
const raw = $json.body ?? {};
const action = String(raw.action ?? "").trim();
const atype  = String(raw.artifact_type ?? "").trim();

if (!action)
  return err("VALIDATION_ERROR", "Missing action field.");
if (!OK_ACTIONS.has(action))
  return err("ACTION_NOT_ALLOWED", "This action is not available in the demo environment.");

// ════════════ artifact.save ════════════
if (action === "artifact.save") {
  if (!atype)
    return err("VALIDATION_ERROR", "Missing artifact_type. Allowed: journal, project, snapshot.");
  if (!OK_TYPES.has(atype))
    return err("TYPE_NOT_ALLOWED", "This artifact type is not available in the demo environment.");

  const title   = String(raw.title ?? "");
  const summary = String(raw.summary ?? "");

  if (title.length > 200 || summary.length > 1000)
    return err("FIELD_TOO_LONG",
      "Titles must be under 200 characters and summaries under 1000 characters.");

  if (raw.content && JSON.stringify(raw.content).length > 4096)
    return err("PAYLOAD_TOO_LARGE",
      "The content exceeds the demo size limit. Please keep entries concise.");

  // Reject parent_artifact_id (not supported in v1)
  if (raw.parent_artifact_id)
    return err("PARENT_NOT_SUPPORTED",
      "Parent-linked artifacts are not supported in the demo. Please create top-level artifacts.");

  // Tag governance: inject mandatory, strip forbidden, cap at 10
  let userTags = Array.isArray(raw.tags)
    ? raw.tags.filter(t => typeof t === "string" && !BAN_TAGS.has(t))
    : [];
  let tags = [...new Set([...MUST_TAGS, ...userTags])];
  if (tags.length > 10) tags = tags.slice(0, 10);

  // Build extension based on artifact_type (required fields per DDL)
  let extension = {};
  if (atype === "project") {
    // lifecycle_stage is NOT NULL — demo projects always start as seed
    extension = { lifecycle_stage: "seed" };
  } else if (atype === "snapshot") {
    // payload is NOT NULL jsonb — use content if provided, otherwise empty object
    extension = { payload: raw.content ?? {} };
  } else if (atype === "journal") {
    // entry_text is nullable — use summary as entry text if no content provided
    extension = { entry_text: summary || title };
  }

  return [{ json: {
    _route: "ok",
    gw_action: "artifact.save",
    gw_workspace_id: DEMO_WS,
    artifact_type: atype,
    title,
    summary: summary || null,
    content: raw.content ?? null,
    tags,
    semantic_type_id: SEM_TYPE,
    owner_user_id: OWNER,
    parent_artifact_id: null,
    extension,
  }}];
}

// ════════════ artifact.list ════════════
if (action === "artifact.list") {
  if (!atype)
    return err("VALIDATION_ERROR",
      "Please specify an artifact type (journal, project, or snapshot).");
  if (!OK_TYPES.has(atype))
    return err("TYPE_NOT_ALLOWED", "This artifact type is not available in the demo environment.");

  const limit  = Math.min(Math.max(Number(raw.limit) || 10, 1), 20);
  const offset = Math.max(Number(raw.offset) || 0, 0);

  return [{ json: {
    _route: "ok",
    gw_action: "artifact.list",
    gw_workspace_id: DEMO_WS,
    artifact_type: atype,
    selector: { limit, offset },
  }}];
}

// ════════════ artifact.query ════════════
if (action === "artifact.query") {
  if (!atype)
    return err("VALIDATION_ERROR",
      "Missing artifact_type for query. Allowed: journal, project, snapshot.");
  if (!OK_TYPES.has(atype))
    return err("TYPE_NOT_ALLOWED", "This artifact type is not available in the demo environment.");
  if (!raw.artifact_id)
    return err("VALIDATION_ERROR", "Missing artifact_id for query.");

  return [{ json: {
    _route: "ok",
    gw_action: "artifact.query",
    gw_workspace_id: DEMO_WS,
    artifact_type: atype,
    artifact_id: raw.artifact_id,
  }}];
}

return err("VALIDATION_ERROR", "Unhandled action.");

// NQxb_Demo_Proxy_v1__Shape_Demo_Response
// Purpose: Translate sub-workflow output into clean demo-friendly JSON.
// Strips internal fields (workspace_id, owner_user_id, semantic_type_id).
// Translates Gateway error codes to friendly messages.
// Handles all 3 actions: save, list, query.

const j = $json ?? {};
const enforce = $node["NQxb_Demo_Proxy_v1__Enforce_And_Translate"].json;
const action = enforce.gw_action;

// ── Internal fields to strip ──
const STRIP = new Set([
  "workspace_id", "owner_user_id", "semantic_type_id",
  "gw_workspace_id", "gw_action", "_gw_route", "_gw_debug",
  "_merge_role", "_frozen_artifact_type", "_frozen_workspace_id",
  "_frozen_extension", "_owner_source", "_route",
]);

// ── Friendly error messages ──
const FRIENDLY = {
  "TYPE_MISMATCH":     "That artifact is a different type than requested.",
  "NOT_FOUND":         "I couldn't find that artifact. It may have been cleaned up.",
  "VALIDATION_ERROR":  "Something wasn't quite right with that request. Let me try again.",
};

// ── Recursive field stripper ──
function clean(obj) {
  if (Array.isArray(obj)) return obj.map(clean);
  if (obj && typeof obj === "object") {
    const out = {};
    for (const [k, v] of Object.entries(obj)) {
      if (!STRIP.has(k)) out[k] = clean(v);
    }
    return out;
  }
  return obj;
}

// ── Error handling ──
if (j.ok === false || (j.error && typeof j.error === "object")) {
  const code = j.error?.code ?? "UNKNOWN";
  return [{ json: {
    ok: false,
    error: {
      code,
      message: FRIENDLY[code] ?? "Something unexpected happened. Let's try something else."
    }
  }}];
}

// ── Save response ──
if (action === "artifact.save") {
  const artifact_id =
    j.artifact_id ?? j.saved_artifact_id ??
    j.data?.artifact_id ?? j.data?.artifact?.artifact_id ?? null;

  return [{ json: {
    ok: true,
    artifact_id,
    artifact_type: enforce.artifact_type,
    title: enforce.title,
    message: "Your artifact has been saved to the demo workspace."
  }}];
}

// ── List response ──
if (action === "artifact.list") {
  // List sub-workflow may return canonical envelope or raw rows
  let artifacts = [];
  if (j.data?.artifacts && Array.isArray(j.data.artifacts)) {
    // Canonical envelope: { ok, data: { artifacts: [...] } }
    artifacts = j.data.artifacts;
  } else if (Array.isArray(j.artifacts)) {
    artifacts = j.artifacts;
  } else if (Array.isArray(j)) {
    artifacts = j;
  }

  return [{ json: {
    ok: true,
    artifacts: clean(artifacts),
    count: artifacts.length,
  }}];
}

// ── Query response ──
if (action === "artifact.query") {
  // Query sub-workflow may return: { ok, data: { artifact } } or raw artifact
  let artifact = null;
  if (j.data?.artifact && typeof j.data.artifact === "object") {
    artifact = j.data.artifact;
  } else if (j.artifact && typeof j.artifact === "object") {
    artifact = j.artifact;
  } else {
    // Raw artifact at top level
    artifact = j;
  }

  return [{ json: {
    ok: true,
    artifact: clean(artifact),
  }}];
}

// Fallback
return [{ json: { ok: true, ...clean(j) } }];
